// Universal Uplink Tracker for TTN v3 JSON
let device = msg.device_id
    || (msg.end_device_ids && msg.end_device_ids.device_id)
    || (msg.payload && msg.payload.end_device_ids && msg.payload.end_device_ids.device_id)
    || (msg.topic && msg.topic.match(/devices\/(.+?)\/up/) ? msg.topic.match(/devices\/(.+?)\/up/)[1] : null);

let ts = msg.timestamp ? (msg.timestamp * 1000) : Date.now();

// TTN v3 decoded payload path
let decoded = null;
if (msg.payload && msg.payload.uplink_message && msg.payload.uplink_message.decoded_payload) {
    decoded = msg.payload.uplink_message.decoded_payload;
}

// Store in global context
if (device) {
    global.set("last_seen_" + device, ts);
    if (decoded && typeof decoded.soil_pct !== "undefined") global.set(device + "_soil_pct", decoded.soil_pct);
    if (decoded && typeof decoded.temperatureF !== "undefined") global.set(device + "_tempF", decoded.temperatureF);
    if (decoded && typeof decoded.battery_mV !== "undefined") global.set(device + "_battery_mV", decoded.battery_mV);

    node.status({ fill: "green", shape: "dot", text: `${device} @ ${new Date(ts).toLocaleTimeString()}` });
} else {
    node.warn("No device id found in uplink");
}

return msg;

// Soil Moisture Formatter for dashboard
let device = (msg.payload && msg.payload.end_device_ids) ? msg.payload.end_device_ids.device_id : null;
let decoded = (msg.payload && msg.payload.uplink_message && msg.payload.uplink_message.decoded_payload) 
              ? msg.payload.uplink_message.decoded_payload : null;
if (device && decoded && typeof decoded.soil_pct !== "undefined") {
    msg.topic = device + " Soil Moisture";
    msg.payload = { device, soil_pct: decoded.soil_pct, battery_mV: decoded.battery_mV || null, last_seen: new Date(global.get("last_seen_"+device)||0).toLocaleString() };
    return msg;
}
return null;

// Relay Temperature Formatter for dashboard
let device = (msg.payload && msg.payload.end_device_ids) ? msg.payload.end_device_ids.device_id : null;
let decoded = (msg.payload && msg.payload.uplink_message && msg.payload.uplink_message.decoded_payload) 
              ? msg.payload.uplink_message.decoded_payload : null;
if (device && decoded && typeof decoded.temperatureF !== "undefined") {
    msg.topic = device + " Temperature";
    msg.payload = { device, tempF: decoded.temperatureF, last_seen: new Date(global.get("last_seen_"+device)||0).toLocaleString() };
    return msg;
}
return null;

// --- GPM Lookup Table ---
const flowRates = {
    "relay-node1-6": 1.5,
    "relay-node1-7": 2.2,
    "relay-node1-8": 0.8,
    "relay-node1-9": 1.1,
    "relay-node-2-6": 3.0,
    "relay-node-2-7": 1.5,
    "relay-node-2-8": 1.5,
    "relay-node-2-9": 0.5
};

let log = global.get("daily_water_log") || [];
let selectedRelayID = flow.get("selected_relay_id") || "unknown";
let startTime = flow.get("relay_start_time");

if (msg.payload && typeof msg.payload === "string" && !msg.topic) {
    flow.set("selected_relay_id", msg.payload);
    return null;
}

if (msg.topic === "relay_state") {
    if (msg.payload === 1) {
        flow.set("relay_start_time", Date.now());
    } 
    else if (msg.payload === 0 && startTime) {
        let durationMin = (Date.now() - startTime) / 60000;
        let activeGPM = flowRates[selectedRelayID] || 1.0;
        let gallonsUsed = durationMin * activeGPM;

        let entry = {
            timestamp: new Date().toLocaleString(),
            relay_id: selectedRelayID,
            gallons: gallonsUsed.toFixed(2),
            duration_min: durationMin.toFixed(2)
        };

        log.push(entry);
        global.set("daily_water_log", log);
        msg.payload = entry;
        return msg;
    }
}
return null;

// --- Threshold Configuration (Distance in mm) ---
const EMERGENCY_LEVEL = 200; 
const WARNING_LEVEL   = 500;
const ALERT_LEVEL     = 1000;

// SAFETY CHECK: Handle both {"distance": 150} AND raw 150
let distance = (typeof msg.payload === 'object') ? msg.payload.distance : msg.payload;

// If distance is missing or not a number, stop and show error on node
if (distance === undefined || isNaN(distance)) {
    node.status({fill:"red", shape:"ring", text:"Error: No distance data"});
    return null; 
}

let status = "Normal";
let severity = 0; 

if (distance <= EMERGENCY_LEVEL) {
    status = "EMERGENCY: Sewer Backup Imminent!";
    severity = 3;
} else if (distance <= WARNING_LEVEL) {
    status = "WARNING: Sewer Level High";
    severity = 2;
} else if (distance <= ALERT_LEVEL) {
    status = "ALERT: Sewer Level Rising";
    severity = 1;
}

// Update the node's visual status in the editor
if (severity > 0) {
    node.status({fill:"red", shape:"dot", text: status + " (" + distance + "mm)"});

    // Create a CLEAN message to prevent crosstalk
    return {
        payload: {
            level: distance,
            status: status,
            severity: severity,
            timestamp: new Date().toLocaleString()
        }
    };
} else {
    node.status({fill:"green", shape:"dot", text:"Level Normal (" + distance + "mm)"});
    return null; // Stop flow if everything is fine
}

// Irrigation Scheduler (global context)
let moistureThresholds = {
    ss1: 40, ss2: 40, ss3: 40, ss4: 40,
    ss5: 40, ss6: 40, ss7: 40, ss8: 40
};

let valveMap = {
    ss1: { vnode: 'relay-node1', fport: 6 },
    ss2: { vnode: 'relay-node1', fport: 7 },
    ss3: { vnode: 'relay-node1', fport: 8 },
    ss4: { vnode: 'relay-node1', fport: 9 },
    ss5: { vnode: 'relay-node-2', fport: 6 },
    ss6: { vnode: 'relay-node-2', fport: 7 },
    ss7: { vnode: 'relay-node-2', fport: 8 },
    ss8: { vnode: 'relay-node-2', fport: 9 }
};

let schedule = {
    "relay-node1": [0, 2, 4],    // Sunday, Tuesday, Thursday
    "relay-node-2": [1, 3, 5]    // Monday, Wednesday, Friday
};

let now = new Date();
let dow = now.getDay();
let scheduleType = msg.topic || 'scheduled';
let delay = 0;

let interval = global.get("irrigation_interval") || 5 * 60 * 1000;
let failsafeMinutes = global.get("failsafe_minutes") || 1;
let rain = global.get("rain_override") || false;

if (rain) {
    node.warn("Irrigation skipped due to rain override.");
    return null;
}

function sendDown(vnode, fport, on) {
    node.send([{
        topic: `v3/5571-258-irri@ttn/devices/${vnode}/down/push`,
        payload: {
            downlinks: [{
                frm_payload: Buffer.from([on ? 1 : 0]).toString('base64'),
                f_port: fport,
                confirmed: true,
                priority: "NORMAL"
            }]
        },
        qos: 1,
        retain: false
    }, null]);
}

for (let vnode in schedule) {
    if (scheduleType === 'scheduled' && !schedule[vnode].includes(dow)) continue;

    for (let sensor in valveMap) {
        let map = valveMap[sensor];
        if (map.vnode !== vnode) continue;

        let moisture = global.get(sensor + "_soil_pct") || 0;
        let temp = global.get(vnode + "_tempF") || 80;
        let threshold = moistureThresholds[sensor];
        let hot = temp >= 100;

        let shouldRun =
            (scheduleType === 'scheduled' && moisture <= threshold) ||
            ((scheduleType === 'override-4pm' || scheduleType === 'override-6pm') && hot && moisture <= threshold);

        if (shouldRun) {
            setTimeout(() => sendDown(vnode, map.fport, true), delay);
            setTimeout(() => sendDown(vnode, map.fport, false), delay + interval);
            delay += interval;
        }
    }
}

// Global failsafe OFF
setTimeout(() => {
    node.warn(`Failsafe OFF: buffer ${failsafeMinutes} min`);
    for (let sensor in valveMap) {
        let map = valveMap[sensor];
        sendDown(map.vnode, map.fport, false);
    }
}, delay + interval + failsafeMinutes * 60 * 1000);

return null;

// Send OFF to all valve ports immediately
let valveMap = [
    { vnode: 'relay-node1', fport: 6 }, { vnode: 'relay-node1', fport: 7 },
    { vnode: 'relay-node1', fport: 8 }, { vnode: 'relay-node1', fport: 9 },
    { vnode: 'relay-node-2', fport: 6 }, { vnode: 'relay-node-2', fport: 7 },
    { vnode: 'relay-node-2', fport: 8 }, { vnode: 'relay-node-2', fport: 9 }
];

let msgs = valveMap.map(v => ({
    topic: `v3/5571-258-irri@ttn/devices/${v.vnode}/down/push`,
    payload: {
        downlinks: [
            {
                frm_payload: Buffer.from([0]).toString('base64'),
                f_port: v.fport,
                confirmed: true,
                priority: "NORMAL"
            }
        ]
    },
    qos: 1,
    retain: false
}));

return [msgs];

// Build soil & relay tables from global context

let devices = ["ss1", "ss2", "ss3", "ss4", "ss5", "ss6", "ss7", "ss8"];
let soil = [];

for (let d of devices) {
    soil.push({
        device: d,
        soil_pct: global.get(d + "_soil_pct"),
        battery_mV: global.get(d + "_battery_mV"),
        last_seen: (function () {
            let ts = global.get("last_seen_" + d);
            return ts ? new Date(ts).toLocaleString() : "";
        })()
    });
}

let relays = ["relay-node1", "relay-node-2"];
let relayRows = [];

for (let r of relays) {
    relayRows.push({
        device: r,
        tempF: global.get(r + "_tempF"),
        last_seen: (function () {
            let ts = global.get("last_seen_" + r);
            return ts ? new Date(ts).toLocaleString() : "";
        })()
    });
}

// Output 1 = soil table, Output 2 = relay table
return [
    { payload: soil },
    { payload: relayRows }
];

// Build TTN downlink from relay selection + ON/OFF switch state
let sel = global.get("relay_selection"); // e.g., "relay-node1-6"
if (!sel) {
    node.warn("No relay selected");
    return null;
}

let m = sel.match(/^(relay-node1|relay-node-2)-(\d+)$/);
if (!m) {
    node.warn("Bad relay selection format: " + sel);
    return null;
}

let vnode = m[1];          // relay-node1 or relay-node-2
let fport = Number(m[2]);  // port number from dropdown
let on = Number(msg.payload) === 1;  // switch state → 1=ON, 0=OFF

// Build downlink message for TTN
msg.topic = `v3/5571-258-irri@ttn/devices/${vnode}/down/push`;
msg.payload = {
    downlinks: [
        {
            frm_payload: Buffer.from([on ? 1 : 0]).toString('base64'),
            f_port: fport,
            confirmed: true,
            priority: "NORMAL"
        }
    ]
};
msg.qos = 1;
msg.retain = false;

return msg;

// If the incoming message doesn't have a 'manual' trigger or isn't from the timer, STOP.
if (!msg.payload || msg.payload.status) { 
    return null; 
}
// Daily Summary + Alerts (global context)
let now = new Date();
let hour = now.getHours();

let summaryHour = global.get("maint_report_hour") || 7;
let lastSent = global.get("daily_summary_last_sent") || "";
let todayKey = now.toISOString().slice(0, 10) + "-" + summaryHour;

// Only send once per day at the configured hour
//if (hour !== summaryHour || lastSent === todayKey) {
//
  //  return null;
//}

let thresholdHrs = global.get("alert_threshold_hours") || 4;
let thresholdMs = thresholdHrs * 60 * 60 * 1000;

let devices = [
    "ss1", "ss2", "ss3", "ss4", "ss5", "ss6", "ss7", "ss8",
    "relay-node1", "relay-node-2"
];

let interval = global.get("irrigation_interval") || 300000;
let failsafe = global.get("failsafe_minutes") || 1;
let rain = global.get("rain_override") || false;

let nowMs = Date.now();
let lastSeenLines = [];
let soilLines = [];
let tempLines = [];
let batteryLines = [];
let offline = [];

for (let d of devices) {
    let ts = global.get("last_seen_" + d);
    if (ts) {
        let mins = ((nowMs - ts) / 60000).toFixed(1);
        lastSeenLines.push(`${d}: ${new Date(ts).toLocaleString()} (${mins} min ago)`);
        if (nowMs - ts > thresholdMs) {
            offline.push(`❌ ${d} offline > ${thresholdHrs} hrs`);
        }
    } else {
        lastSeenLines.push(`${d}: never`);
        offline.push(`❌ ${d} never seen`);
    }

    let s = global.get(d + "_soil_pct");
    if (typeof s !== "undefined") {
        soilLines.push(`${d}: ${s}%`);
    }

    let b = global.get(d + "_battery_mV");
    if (typeof b !== "undefined") {
        batteryLines.push(`${d}: ${b} mV`);
    }
}

for (let r of ["relay-node1", "relay-node-2"]) {
    let t = global.get(r + "_tempF");
    if (typeof t !== "undefined") {
        tempLines.push(`${r}: ${t}°F`);
    }
}

let body = `
🌱 Irrigation System Daily Summary

⏱ Interval: ${(interval / 60000)} min
🛑 Failsafe: ${failsafe} min
🌧 Rain override: ${rain}

📡 Last Seen:
${lastSeenLines.join("\n")}

💧 Soil Moisture:
${soilLines.length ? soilLines.join("\n") : "No data"}

🔋 Soil Battery:
${batteryLines.length ? batteryLines.join("\n") : "No data"}

🌡 Temps:
${tempLines.length ? tempLines.join("\n") : "No data"}
`;

if (offline.length > 0) {
    body += `\n\n⚠️ Alerts:\n${offline.join("\n")}`;
}

//msg.topic = "🌱 Daily Irrigation Summary";
//msg.payload = body;,
 //to: "flintellsworth@mac.com"

// 2. Create a brand-new object to KILL all crosstalk
let newMsg = {
    to: "flintellsworth@mac.com",
    topic: "🌱 Daily Irrigation Summary",
    payload: body
};

node.status({fill:"green", shape:"ring", text:"Report sent to flintellsworth@mac.com"});

// Mark sent
global.set("daily_summary_last_sent", todayKey);
return newMsg;

msg.topic = "🌱 Test Irrigation Summary";
msg.payload = "This is a test email from Node-RED.";
return msg;

// 1. Get the target hour from your Dashboard setting (0-23)
const targetHour = global.get("water_report_hour") || 20; 
const currentHour = new Date().getHours();

// 2. Only proceed if the current hour matches your setting
if (currentHour !== parseInt(targetHour)) {
    node.status({fill:"grey", shape:"dot", text:"Waiting for hour " + targetHour});
    return null; 
}

// 3. Retrieve the log
let log = global.get("daily_water_log") || [];
let newMsg = { to: "flintellsworth@mac.com" };

if (log.length === 0) {
    newMsg.topic = "Daily Water Report: No usage recorded.";
    newMsg.payload = "No irrigation events occurred in the last 24 hours.";
} else {
    let totalGallons = 0;
    let reportBody = "Daily Irrigation Summary\n--------------------------\n";

    log.forEach(entry => {
        reportBody += `${entry.timestamp} | ${entry.relay_id} | ${entry.gallons} gal (${entry.duration_min} min)\n`;
        totalGallons += parseFloat(entry.gallons);
    });

    reportBody += "\n--------------------------\n";
    reportBody += `TOTAL WATER USED: ${totalGallons.toFixed(2)} Gallons`;

    newMsg.topic = `Daily Water Report: ${totalGallons.toFixed(1)} Gallons Used`;
    newMsg.payload = reportBody;
}

// 4. CRITICAL: Clear the log so tomorrow starts fresh
global.set("daily_water_log", []);

node.status({fill:"green", shape:"ring", text:"Report sent to flintellsworth@mac.com"});
return newMsg; // This now sends the email regardless of usage

// 1. Capture what we need from the incoming sewer data
let data = msg.payload; 

// 2. Return a BRAND NEW object. 
// This kills any 'msg.topic' or 'msg.payload' from previous nodes.
return {
    to: "flintellsworth@mac.com",
    topic: "🚨 " + (data.status || "Sewer Alert"),
    payload: `
    *** SEWER MONITORING ALERT ***

    Status: ${data.status}
    Water Level: ${data.level}mm
    Severity: Level ${data.severity}
    Logged At: ${data.timestamp}

    ACTION: Please check the standpipe immediately.
    `
};
